import{_ as t,o as r,c as i,a2 as e}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"留存活动","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/activities/asset-retention.md","filePath":"zh-CN/rewards/activities/asset-retention.md"}'),l={name:"rewards/activities/asset-retention.md"};function o(d,a,n,h,s,u){return r(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="留存活动" tabindex="-1">留存活动 <a class="header-anchor" href="#留存活动" aria-label="Permalink to &quot;留存活动&quot;">​</a></h1><p>留存活动（Retain Activity）是 LongBridge 平台为激励用户留存资金而推出的奖励活动，根据触发场景分为四种类型：</p><ul><li>出金挽留（Withdraw）：用户发起出金申请时触发，引导用户取消出金并维持资产</li><li>净入金留存（NetDeposit）：用户完成净入金后触发，激励持续保持入金资产</li><li>净转入留存（NetTransfer）：用户完成净资产转入后触发</li><li>净转仓留存（NetRollover）：用户完成净资产转仓后触发</li></ul><p>最常见的类型是出金挽留。所有留存活动的核心逻辑是「留住资金、给予回报」。</p><h2 id="参与条件" tabindex="-1">参与条件 <a class="header-anchor" href="#参与条件" aria-label="Permalink to &quot;参与条件&quot;">​</a></h2><ul><li>已注册 LongBridge 账户并完成实名认证（KYC）</li><li>账户内有可出金的资金</li><li>在特定触发场景下（如发起出金时）收到留存活动邀请</li><li>部分留存活动需主动在「活动中心」报名参与</li><li>账户所属地区/持牌人在活动覆盖范围内</li></ul><h2 id="任务类型" tabindex="-1">任务类型 <a class="header-anchor" href="#任务类型" aria-label="Permalink to &quot;任务类型&quot;">​</a></h2><ul><li>资产留存任务：账户净资产维持在指定金额以上，满足指定天数</li><li>取消出金任务：取消当前出金申请，将资金留在账户内</li><li>持续持仓任务：在指定时间段内持续持有一定市值的股票</li><li>入金留存任务：重新入金并维持账户余额满足条件</li><li>阶梯留存任务：根据留存资产规模和天数获得不同档位的奖励</li></ul><h2 id="参与步骤" tabindex="-1">参与步骤 <a class="header-anchor" href="#参与步骤" aria-label="Permalink to &quot;参与步骤&quot;">​</a></h2><ol><li>触发留存活动邀请（通常在发起出金流程中弹出）或在「活动中心」找到活动</li><li>查看活动规则，了解需要满足的留存条件和对应奖励</li><li>选择接受留存（取消出金或维持资产）</li><li>系统开始计算留存时间/资产</li><li>在规定期限内持续满足留存条件</li><li>留存条件达成后奖励自动发放</li><li>在「活动中心 → 我的奖励」查看奖励状态</li></ol><h2 id="任务完成判定" tabindex="-1">任务完成判定 <a class="header-anchor" href="#任务完成判定" aria-label="Permalink to &quot;任务完成判定&quot;">​</a></h2><ul><li>资产留存：以账户在每日收市后的净资产快照为统计依据</li><li>留存天数：以连续满足资产要求的自然日（HKT）计算</li><li>中途资产低于门槛的日期可能不计入有效留存天数</li><li>系统每天香港时间 1:00 和 17:00 各检查一次留存状态（17:00 对应港股收市后），奖励在检查后触发发放流程</li><li>具体判定规则以活动详情页为准</li></ul><h2 id="奖励类型" tabindex="-1">奖励类型 <a class="header-anchor" href="#奖励类型" aria-label="Permalink to &quot;奖励类型&quot;">​</a></h2><ul><li>现金奖励：直接发放至账户可用余额</li><li>高息定存券：在指定期间内对账户资金提供额外利息</li><li>交易券/现金券：抵扣手续费或使用优惠</li><li>加息凭证：叠加在现有利率上的额外收益凭证</li></ul><h2 id="发放时机" tabindex="-1">发放时机 <a class="header-anchor" href="#发放时机" aria-label="Permalink to &quot;发放时机&quot;">​</a></h2><p>留存条件达成后系统自动触发发放（全自动模式）。部分活动配置为需要手动领取：留存达标后，活动页面出现「领取奖励」按钮，须主动点击才能触发发放。奖励发放通常有一定延迟，可能在条件达成后<br> 1-5 个工作日内到账。留存活动奖励发放存在明显延迟是正常现象，系统需要完成留存天数验证、资产核对等步骤后才触发发放。具体发放方式（自动/手动）和时机以活动详情页说明为准。</p><h2 id="奖励状态说明" tabindex="-1">奖励状态说明 <a class="header-anchor" href="#奖励状态说明" aria-label="Permalink to &quot;奖励状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th><th>用户操作</th></tr></thead><tbody><tr><td>待发放</td><td>留存任务已确认，奖励等待处理</td><td>无需操作，等待系统处理</td></tr><tr><td>发放中</td><td>系统正在将奖励发送至账户</td><td>等待，通常数小时内完成</td></tr><tr><td>已发放</td><td>奖励已成功到账</td><td>可在账户余额中查看</td></tr><tr><td>锁定中</td><td>奖励已到账但处于锁定期</td><td>等待锁定期结束自动解锁</td></tr><tr><td>已解锁可用</td><td>锁定期结束，可正常使用</td><td>正常使用奖励</td></tr><tr><td>发放失败</td><td>奖励发放失败</td><td>联系客服处理</td></tr><tr><td>已取消</td><td>奖励因未满足条件或规则原因取消</td><td>联系客服确认原因</td></tr></tbody></table><h2 id="锁定期说明" tabindex="-1">锁定期说明 <a class="header-anchor" href="#锁定期说明" aria-label="Permalink to &quot;锁定期说明&quot;">​</a></h2><p>留存活动奖励常配有锁定期设计。奖励发放后状态显示「锁定中（Lockup）」，在锁定期内不可提现或使用。锁定期结束后系统自动解锁，状态变为「已解锁可用（Used）」。锁定期通常从奖励发放之日起计算，具体时长（如<br> 30 天、90 天等）以活动规则为准。</p><blockquote></blockquote><p>锁仓期的完整机制说明（计算规则、违约后果等）请参见<a href="/wiki/rewards/rewards-overview#锁仓期机制">奖励系统 · 锁仓期机制</a>。</p><h2 id="多选一奖励" tabindex="-1">多选一奖励 <a class="header-anchor" href="#多选一奖励" aria-label="Permalink to &quot;多选一奖励&quot;">​</a></h2><p>部分留存活动设置&quot;多选一&quot;奖励：达标后展示多组奖励方案，用户选择其中一组领取。选择后无法更改，其他方案自动进入「已领取其他奖励」状态。若活动设有领取截止时间，须在截止前完成选择和领取。</p><h2 id="资产计算与奖励发放答疑" tabindex="-1">资产计算与奖励发放答疑 <a class="header-anchor" href="#资产计算与奖励发放答疑" aria-label="Permalink to &quot;资产计算与奖励发放答疑&quot;">​</a></h2><p><strong>Q：我已经满足了留存条件，但奖励一直没到账，是什么原因？</strong><br> A：留存活动奖励发放通常有一定延迟，留存条件达成后系统需要进行后台核对（验证留存天数、资产水位等），处理时间可能需要 1-5<br> 个工作日甚至更长。请在「活动中心 → 我的奖励」查看奖励状态，如显示「待发放（Pending）」说明正在处理中，请耐心等待。如超过活动详情页约定的发放时间仍未到账，请联系客服。</p><p><strong>Q：奖励显示「锁定中（Lockup）」，什么时候能用？</strong><br> A：锁定中状态表示奖励已成功记录到您的账户，但正处于锁定期内，暂时无法使用。锁定期结束后系统会自动将状态更改为「已解锁可用（Used）」，届时您可以正常使用该奖励。您可以在「我的奖励」详情中查看预计解锁日期。锁定期通常从奖励发放日起计算，以活动规则为准。</p><p><strong>Q：我的留存活动奖励到账了，但被锁定了 90 天，为什么这么久？</strong><br> A：留存活动的锁定期是活动设计的一部分，目的是确保资金真正留存在平台内。锁定期长短（30 天、90<br> 天等）在活动规则中有明确说明，参与前可在活动详情页确认锁定期条款。如您对锁定期有异议，请联系客服核实活动规则是否已充分告知。</p><p><strong>Q：我中途把账户里的钱出金了，之前满足的留存天数还算吗？</strong><br> A：通常不算。出金导致账户资产低于留存门槛后，中断前已积累的留存天数可能会失效，出金当日起不再计入有效留存。具体规则以活动说明为准，部分活动允许资产短暂波动，部分活动则严格要求全程保持门槛。建议在参与留存活动期间避免出金操作。</p><p><strong>Q：奖励显示「发放失败（Failed）」，我能重新申请吗？</strong><br> A：发放失败的主要原因包括：（1）账户 KYC 未完成；（2）账户被冻结或限制；（3）系统技术问题。您无需重新申请，请联系客服提供奖励详情，客服会协助排查失败原因并重新触发发放（如果符合条件）。</p><p><strong>Q：留存活动弹出后我没有接受，之后还能参与吗？</strong><br> A：这取决于活动规则。部分活动仅在特定触发场景（如出金流程中）弹出一次，错过后无法再次触发；部分活动支持在「活动中心」主动报名参与。建议在出金流程中仔细查看留存活动条款再决定是否参与，或在「活动中心」查找同期可参与的留存活动。</p><p><strong>Q：留存活动达标了，但奖励页面显示需要手动领取，怎么操作？</strong><br> A：部分留存活动的奖励不会自动发放，需要您主动领取。请回到活动详情页，找到「领取奖励」按钮并点击。若活动配置了多组奖励供选择，需在页面上选择您想要的那组方案再点击领取。请注意领取可能有时间限制，建议尽早操作，逾期可能无法补领。</p><p><strong>Q：留存活动说的「资产」包括哪些？股票市值算吗？</strong><br> A：留存活动中的「资产」通常包括账户现金余额和持仓股票市值。具体计算口径（是否包含未结算资金、期权价值等）以活动详情页说明为准。建议在活动开始前确认自己的账户总资产是否满足要求，确保符合留存条件。</p><p><strong>Q：我持仓的股票跌了，账户总资产低于门槛了，留存天数还算吗？</strong><br> A：不算。留存活动以「每日收市后净资产快照」为判定依据，当日收市后净资产低于门槛的日期不计入有效留存天数。股票市值下跌导致资产低于门槛与主动出金效果相同，该日不计入有效留存。您可以选择补充入金以恢复资产至门槛以上（以具体活动规则为准），从满足条件的次日起重新累计有效留存天数。</p><h2 id="奖励领取说明" tabindex="-1">奖励领取说明 <a class="header-anchor" href="#奖励领取说明" aria-label="Permalink to &quot;奖励领取说明&quot;">​</a></h2><h3 id="股票奖励" tabindex="-1">股票奖励 <a class="header-anchor" href="#股票奖励" aria-label="Permalink to &quot;股票奖励&quot;">​</a></h3><h4 id="长桥香港" tabindex="-1">长桥香港 <a class="header-anchor" href="#长桥香港" aria-label="Permalink to &quot;长桥香港&quot;">​</a></h4><p>留存门槛达标后，「我的」页面将展示领取入口，请在 <strong>60 个自然日</strong>内前往领取。</p><p>领取后请前往「奖励纪录」使用，系统将在当日发放股票至账户。</p><h4 id="长桥新加坡" tabindex="-1">长桥新加坡 <a class="header-anchor" href="#长桥新加坡" aria-label="Permalink to &quot;长桥新加坡&quot;">​</a></h4><p>股票将在达标后的 <strong>5 个工作日</strong>内，以股票卡形式发放至「长桥 App → 我的 → 我的卡券」。</p><p>请在股票卡有效期内完成查看和兑换。未在有效期内发起兑换，奖励将过期失效，不予补发。</p><p>发起兑换后，股票将在 <strong>10 个工作日</strong>内发放至账户。</p><h3 id="实物奖励" tabindex="-1">实物奖励 <a class="header-anchor" href="#实物奖励" aria-label="Permalink to &quot;实物奖励&quot;">​</a></h3><h4 id="长桥香港-1" tabindex="-1">长桥香港 <a class="header-anchor" href="#长桥香港-1" aria-label="Permalink to &quot;长桥香港&quot;">​</a></h4><p>留存门槛达标后，「我的」页面将展示领取入口，请在 <strong>60 个自然日</strong>内前往领取。</p><p>领取后请前往「奖励纪录」使用，并在获得奖励的 <strong>15 个自然日</strong>内填写收货信息。</p><p>完善收货信息后的 <strong>30 个工作日</strong>内安排采购邮寄，邮寄仅限香港地址。</p><p>过期未填写收货信息视为放弃奖励，不予补发。</p><h2 id="资产计算规则与合规要求" tabindex="-1">资产计算规则与合规要求 <a class="header-anchor" href="#资产计算规则与合规要求" aria-label="Permalink to &quot;资产计算规则与合规要求&quot;">​</a></h2><ul><li>留存奖励到账有延迟，这是正常现象，请耐心等待</li><li>部分留存活动奖励需手动领取，留存达标后请及时到活动页面领取</li><li>多选一奖励活动须主动选择奖励方案，否则视为未领取</li><li>锁定期内奖励不可使用，以活动规则中的锁定期为准</li><li>留存期间避免出金，以免中断留存计数</li><li>股票市值波动导致资产低于门槛，同样影响留存天数计算</li><li>所有活动时间以香港时间（HKT，UTC+8）为准</li><li>奖励查看路径：APP「活动中心 → 我的奖励」</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',53)])])}const b=t(l,[["render",o]]);export{c as __pageData,b as default};
